import { ethers } from "ethers";

const ERC20_ABI = [
  "function name() view returns (string)",
  "function symbol() view returns (string)",
  "function decimals() view returns (uint8)",
  "function balanceOf(address) view returns (uint256)",
  "function allowance(address owner, address spender) view returns (uint256)",
  "function approve(address spender, uint256 amount) returns (bool)",
];

const UNISWAP_V2_ROUTER_ABI = [
  "function WETH() view returns (address)",
  "function getAmountsOut(uint amountIn, address[] calldata path) view returns (uint[] memory amounts)",
  "function swapExactTokensForTokens(uint amountIn, uint amountOutMin, address[] calldata path, address to, uint deadline) returns (uint[] memory amounts)",
  "function swapExactTokensForETH(uint amountIn, uint amountOutMin, address[] calldata path, address to, uint deadline) returns (uint[] memory amounts)",
  "function swapExactETHForTokens(uint amountOutMin, address[] calldata path, address to, uint deadline) payable returns (uint[] memory amounts)",
];

const MAX_UINT256 = (1n << 256n) - 1n;

function isAddress(v) {
  try {
    return ethers.getAddress(v);
  } catch {
    return null;
  }
}

function toBigIntish(v) {
  if (typeof v === "bigint") return v;
  if (typeof v === "number") return BigInt(Math.trunc(v));
  if (typeof v === "string") {
    if (v.startsWith("0x") || v.startsWith("0X")) return BigInt(v);
    if (v.includes(".")) throw new Error("Decimal string not allowed. Use parseUnits for user amounts.");
    return BigInt(v);
  }
  if (v && typeof v === "object" && typeof v.toString === "function") return BigInt(v.toString());
  throw new Error("Unsupported bigintish value");
}

async function waitFor(tx, confirmations = 1) {
  const rec = await tx.wait(confirmations);
  return rec;
}

export class TokenSwapDApp {
  constructor({
    rpcUrl,
    routerAddress,
    chainId,
    defaultSlippageBps = 50,
    defaultDeadlineSeconds = 1200,
  }) {
    if (!rpcUrl) throw new Error("rpcUrl required");
    if (!isAddress(routerAddress)) throw new Error("routerAddress invalid");
    this.rpcUrl = rpcUrl;
    this.chainId = chainId;
    this.defaultSlippageBps = defaultSlippageBps;
    this.defaultDeadlineSeconds = defaultDeadlineSeconds;

    this.readProvider = new ethers.JsonRpcProvider(rpcUrl, chainId);
    this.routerAddress = ethers.getAddress(routerAddress);
    this.routerRead = new ethers.Contract(this.routerAddress, UNISWAP_V2_ROUTER_ABI, this.readProvider);

    this.browserProvider = null;
    this.signer = null;
    this.account = null;
    this.routerWrite = null;
  }

  async connectWallet() {
    if (!globalThis.ethereum) throw new Error("No injected wallet found");
    this.browserProvider = new ethers.BrowserProvider(globalThis.ethereum);
    await this.browserProvider.send("eth_requestAccounts", []);
    this.signer = await this.browserProvider.getSigner();
    this.account = await this.signer.getAddress();
    this.routerWrite = new ethers.Contract(this.routerAddress, UNISWAP_V2_ROUTER_ABI, this.signer);
    return this.account;
  }

  requireConnected() {
    if (!this.signer || !this.account || !this.routerWrite) throw new Error("Wallet not connected");
  }

  erc20Read(tokenAddress) {
    const addr = isAddress(tokenAddress);
    if (!addr) throw new Error("Invalid token address");
    return new ethers.Contract(addr, ERC20_ABI, this.readProvider);
  }

  erc20Write(tokenAddress) {
    this.requireConnected();
    const addr = isAddress(tokenAddress);
    if (!addr) throw new Error("Invalid token address");
    return new ethers.Contract(addr, ERC20_ABI, this.signer);
  }

  async getTokenMeta(tokenAddress) {
    const c = this.erc20Read(tokenAddress);
    const [name, symbol, decimals] = await Promise.all([c.name(), c.symbol(), c.decimals()]);
    return { address: ethers.getAddress(tokenAddress), name, symbol, decimals: Number(decimals) };
  }

  async getBalance(tokenAddress, owner = null) {
    const addr = owner ? ethers.getAddress(owner) : this.account;
    if (!addr) throw new Error("owner required (or connect wallet)");
    const c = this.erc20Read(tokenAddress);
    return await c.balanceOf(addr);
  }

  async getAllowance(tokenAddress, owner, spender = null) {
    const o = ethers.getAddress(owner);
    const s = ethers.getAddress(spender || this.routerAddress);
    const c = this.erc20Read(tokenAddress);
    return await c.allowance(o, s);
  }

  async approveMax(tokenAddress, spender = null, { confirmations = 1 } = {}) {
    this.requireConnected();
    const s = ethers.getAddress(spender || this.routerAddress);
    const token = this.erc20Write(tokenAddress);

    const current = await token.allowance(this.account, s);
    if (toBigIntish(current) >= MAX_UINT256 / 2n) {
      return { status: "skipped", tx: null, receipt: null, allowance: current };
    }

    const tx = await token.approve(s, MAX_UINT256);
    const receipt = await waitFor(tx, confirmations);
    const allowance = await token.allowance(this.account, s);
    return { status: "approved", tx, receipt, allowance };
  }

  async ensureAllowance(tokenAddress, amountNeeded, spender = null, opts = {}) {
    this.requireConnected();
    const s = ethers.getAddress(spender || this.routerAddress);
    const token = this.erc20Read(tokenAddress);
    const allowance = await token.allowance(this.account, s);
    const need = toBigIntish(amountNeeded);
    if (toBigIntish(allowance) >= need) return { status: "sufficient", allowance };
    return await this.approveMax(tokenAddress, s, opts);
  }

  async getWETH() {
    return await this.routerRead.WETH();
  }

  async quoteExactIn(amountIn, path) {
    if (!Array.isArray(path) || path.length < 2) throw new Error("path must have >= 2 addresses");
    const normalizedPath = path.map((a) => ethers.getAddress(a));
    const ai = toBigIntish(amountIn);
    const amounts = await this.routerRead.getAmountsOut(ai, normalizedPath);
    return amounts;
  }

  calcAmountOutMin(amountOut, slippageBps = null) {
    const bps = slippageBps == null ? this.defaultSlippageBps : slippageBps;
    const out = toBigIntish(amountOut);
    const min = (out * BigInt(10000 - bps)) / 10000n;
    return min;
  }

  deadline(secondsFromNow = null) {
    const s = secondsFromNow == null ? this.defaultDeadlineSeconds : secondsFromNow;
    return Math.floor(Date.now() / 1000) + s;
  }

  async swapExactTokensForTokens({
    tokenIn,
    tokenOut,
    amountIn,
    slippageBps,
    path = null,
    to = null,
    deadlineSeconds,
    ensureApproval = true,
    confirmations = 1,
  }) {
    this.requireConnected();

    const tIn = ethers.getAddress(tokenIn);
    const tOut = ethers.getAddress(tokenOut);
    const recipient = to ? ethers.getAddress(to) : this.account;
    const p = (path || [tIn, tOut]).map((a) => ethers.getAddress(a));

    const ai = toBigIntish(amountIn);
    if (ensureApproval) await this.ensureAllowance(tIn, ai, this.routerAddress, { confirmations });

    const quoted = await this.routerRead.getAmountsOut(ai, p);
    const amountOut = quoted[quoted.length - 1];
    const amountOutMin = this.calcAmountOutMin(amountOut, slippageBps);
    const dl = this.deadline(deadlineSeconds);

    const tx = await this.routerWrite.swapExactTokensForTokens(ai, amountOutMin, p, recipient, dl);
    const receipt = await waitFor(tx, confirmations);
    return { tx, receipt, quoted, amountOutMin };
  }

  async swapExactTokensForETH({
    tokenIn,
    amountIn,
    slippageBps,
    path = null,
    to = null,
    deadlineSeconds,
    ensureApproval = true,
    confirmations = 1,
  }) {
    this.requireConnected();
    const tIn = ethers.getAddress(tokenIn);
    const recipient = to ? ethers.getAddress(to) : this.account;

    const weth = await this.getWETH();
    const p = (path || [tIn, weth]).map((a) => ethers.getAddress(a));

    const ai = toBigIntish(amountIn);
    if (ensureApproval) await this.ensureAllowance(tIn, ai, this.routerAddress, { confirmations });

    const quoted = await this.routerRead.getAmountsOut(ai, p);
    const amountOut = quoted[quoted.length - 1];
    const amountOutMin = this.calcAmountOutMin(amountOut, slippageBps);
    const dl = this.deadline(deadlineSeconds);

    const tx = await this.routerWrite.swapExactTokensForETH(ai, amountOutMin, p, recipient, dl);
    const receipt = await waitFor(tx, confirmations);
    return { tx, receipt, quoted, amountOutMin };
  }

  async swapExactETHForTokens({
    tokenOut,
    amountInWei,
    slippageBps,
    path = null,
    to = null,
    deadlineSeconds,
    confirmations = 1,
  }) {
    this.requireConnected();

    const tOut = ethers.getAddress(tokenOut);
    const recipient = to ? ethers.getAddress(to) : this.account;

    const weth = await this.getWETH();
    const p = (path || [weth, tOut]).map((a) => ethers.getAddress(a));

    const ai = toBigIntish(amountInWei);

    const quoted = await this.routerRead.getAmountsOut(ai, p);
    const amountOut = quoted[quoted.length - 1];
    const amountOutMin = this.calcAmountOutMin(amountOut, slippageBps);
    const dl = this.deadline(deadlineSeconds);

    const tx = await this.routerWrite.swapExactETHForTokens(amountOutMin, p, recipient, dl, { value: ai });
    const receipt = await waitFor(tx, confirmations);
    return { tx, receipt, quoted, amountOutMin };
  }

  async parseTokenAmount(tokenAddress, humanAmount) {
    const c = this.erc20Read(tokenAddress);
    const decimals = Number(await c.decimals());
    return ethers.parseUnits(String(humanAmount), decimals);
  }

  async formatTokenAmount(tokenAddress, rawAmount) {
    const c = this.erc20Read(tokenAddress);
    const decimals = Number(await c.decimals());
    return ethers.formatUnits(rawAmount, decimals);
  }
}

export async function createSwapAppFromWindow({
  routerAddress,
  rpcUrl,
  chainId,
  defaultSlippageBps,
  defaultDeadlineSeconds,
}) {
  const app = new TokenSwapDApp({
    rpcUrl,
    routerAddress,
    chainId,
    defaultSlippageBps,
    defaultDeadlineSeconds,
  });
  await app.connectWallet();
  return app;
}